-- N91H00-X9800 BOM 생성 (정보전략 BOM 회신 + Usage 시트 기준)
-- 레벨: 완제품 N91H00-X9800 ← 반제품 C1/C2(전선~일반압착) + 완제품 조립자재
-- 수량: 완제품 1대 전개 = Usage 총소요량 정합. 길이자재 QTY_PER=mm.
-- 가정: 1EA 공통 압착자재(HTEAVCW002MA/DLMLS6-3-3/EKEESNATBC)는 C1에 귀속. VSFT1-201은 C1 압착 1 + 완제품 열수축 1.

-- ===== 1) 품목마스터 누락 투입자재 3종 추가 =====
MERGE INTO ITEM_MASTERS m USING (SELECT 'LB04201250' ITEM_CODE FROM DUAL) s ON (m.ITEM_CODE=s.ITEM_CODE AND m.COMPANY='40')
WHEN NOT MATCHED THEN INSERT (ITEM_CODE, ITEM_NAME, PART_NO, ITEM_TYPE, SPEC, UNIT, COMPANY, PLANT_CD, CREATED_BY)
VALUES ('LB04201250','LABEL','LB04201250','RAW_MATERIAL','LABEL 42mm*12mm Y(LOT 2차원 바코드 라벨)','EA','40','1000','claude');
/
MERGE INTO ITEM_MASTERS m USING (SELECT 'LB08802520' ITEM_CODE FROM DUAL) s ON (m.ITEM_CODE=s.ITEM_CODE AND m.COMPANY='40')
WHEN NOT MATCHED THEN INSERT (ITEM_CODE, ITEM_NAME, PART_NO, ITEM_TYPE, SPEC, UNIT, COMPANY, PLANT_CD, CREATED_BY)
VALUES ('LB08802520','LABEL','LB08802520','RAW_MATERIAL','LABEL 88mm*25mm W(회로 라벨)','EA','40','1000','claude');
/
MERGE INTO ITEM_MASTERS m USING (SELECT 'RIBON-7' ITEM_CODE FROM DUAL) s ON (m.ITEM_CODE=s.ITEM_CODE AND m.COMPANY='40')
WHEN NOT MATCHED THEN INSERT (ITEM_CODE, ITEM_NAME, PART_NO, ITEM_TYPE, SPEC, UNIT, COMPANY, PLANT_CD, CREATED_BY)
VALUES ('RIBON-7','RIBBON','RIBON-7','RAW_MATERIAL','LABEL PRINT용 먹지(RESIN) 110*300(B-325 TYPE)','EA','40','1000','claude');
/

