WHEN NOT MATCHED THEN INSERT (PARENT_ITEM_CODE,CHILD_ITEM_CODE,QTY_PER,SEQ,REVISION,USE_YN,COMPANY,PLANT_CD,CREATED_BY) VALUES ('N91H00-X9800','N91H00-X9800-C1',1,10,'A','Y','40','1000','claude');
